const CalendarView: React.FC<{
    getDayChecks: (d: string) => boolean[],
    onSelectDate: (d: string) => void,
    habitNames: string[],
    onToggleHabit: (d: string, i: number) => void
}> = ({ getDayChecks, onSelectDate, habitNames, onToggleHabit }) => {
    const [currentDate, setCurrentDate] = useState(new Date());
    const [calendarView, setCalendarView] = useState<'year' | 'month' | 'week'>('month');

    const handlePrev = () => { if (calendarView === 'year') setCurrentDate(subYears(currentDate, 1)); if (calendarView === 'month') setCurrentDate(subMonths(currentDate, 1)); if (calendarView === 'week') setCurrentDate(subWeeks(currentDate, 1)); };
    const handleNext = () => { if (calendarView === 'year') setCurrentDate(addYears(currentDate, 1)); if (calendarView === 'month') setCurrentDate(addMonths(currentDate, 1)); if (calendarView === 'week') setCurrentDate(addWeeks(currentDate, 1)); };
    const handleToday = () => setCurrentDate(new Date());

    const daysInMonth = eachDayOfInterval({ start: startOfWeek(startOfMonth(currentDate)), end: endOfWeek(endOfMonth(currentDate)) });

    return (
        <div className="space-y-6 animate-fade-in pb-10" key={habitNames.join(',')}>
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl w-full sm:w-auto">
                    {(['week', 'month', 'year'] as const).map((v) => ( <button key={v} onClick={() => setCalendarView(v)} className={`flex-1 sm:flex-none px-4 py-2 text-sm font-bold rounded-lg transition-all capitalize ${calendarView === v ? 'bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>{v}</button> ))}
                </div>
                <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                    <h2 className="text-lg font-bold text-slate-900 dark:text-white sm:w-48 text-center sm:text-right">{calendarView === 'year' && format(currentDate, 'yyyy')} {calendarView === 'month' && format(currentDate, 'MMMM yyyy')} {calendarView === 'week' && `Week of ${format(startOfWeek(currentDate), 'MMM d')}`}</h2>
                    <div className="flex gap-1 bg-slate-100 dark:bg-slate-900 rounded-lg p-1">
                        <button onClick={handlePrev} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 rotate-90"/></button>
                        <button onClick={handleToday} className="px-3 py-1 text-xs font-bold hover:bg-white dark:hover:bg-slate-800 rounded-md transition-colors">Today</button>
                        <button onClick={handleNext} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 -rotate-90"/></button>
                    </div>
                </div>
            </div>
            <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden min-h-[400px]">
                {calendarView === 'year' && ( <div className="p-6 overflow-x-auto"><div className="min-w-[700px] grid grid-cols-3 gap-x-8 gap-y-8">{Array.from({ length: 12 }).map((_, i) => { const monthDate = new Date(currentDate.getFullYear(), i, 1); const mDays = eachDayOfInterval({ start: startOfMonth(monthDate), end: endOfMonth(monthDate) }); return ( <div key={i} className="space-y-2"><h4 className={`text-sm font-bold ${MONTH_PALETTES[i].styles[3].replace('bg-', 'text-')} dark:${MONTH_PALETTES[i].styles[1].replace('bg-', 'text-')}`}>{format(monthDate, 'MMMM')}</h4><div className="grid grid-cols-7 gap-1">{mDays.map(d => { const dStr = format(d, 'yyyy-MM-dd'); const count = getDayChecks(dStr).filter(Boolean).length; const colorClass = getMonthColor(i, count); const isPastDate = isBefore(d, startOfDay(new Date())); let textColorClass = ''; if (count === 0) textColorClass = 'text-slate-300 dark:text-slate-700'; else if (count <= 6) textColorClass = 'text-slate-900/70'; else textColorClass = 'text-white/90'; return ( <button key={dStr} onClick={() => onSelectDate(dStr)} className={`w-full aspect-square rounded-sm cursor-pointer hover:opacity-80 transition-opacity ${colorClass} flex items-center justify-center text-[8px] font-bold ${textColorClass} relative overflow-hidden`} title={`${dStr}: ${count}/10`}>{isPastDate && count === 0 && ( <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><SpiderWebIcon className="w-full h-full text-red-900/60 dark:text-red-500/60 animate-pulse" strokeWidth={1.5} /></div> )}<span className="relative z-10">{format(d, 'd')}</span></button> )})}</div></div> )})}</div></div> )}
                {calendarView === 'month' && ( <> <div className="grid grid-cols-7 text-center py-3 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 dark:bg-slate-900/50">{['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => <div key={d}>{d}</div>)}</div><div className="grid grid-cols-7 bg-slate-200 dark:bg-slate-700 gap-px">{daysInMonth.map(day => { const dStr = format(day, 'yyyy-MM-dd'); const count = getDayChecks(dStr).filter(Boolean).length; const isCurrentMonth = isSameMonth(day, currentDate); const isTodayDate = isToday(day); const message = getDailyMessage(dStr, count); const isPastDate = isBefore(day, startOfDay(new Date())); return ( <button key={dStr} onClick={() => onSelectDate(dStr)} className={`min-h-[80px] sm:min-h-[112px] p-1 sm:p-2 flex flex-col justify-between items-start transition-colors hover:bg-indigo-50 dark:hover:bg-indigo-900/10 relative group ${!isCurrentMonth ? 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600' : 'bg-white dark:bg-slate-800'}`}>{isPastDate && count === 0 && ( <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0"><SpiderWebIcon className="w-12 h-12 sm:w-20 sm:h-20 text-red-900/40 dark:text-red-500/40 animate-pulse" /></div> )}<div className="flex justify-between w-full relative z-10"><span className={`text-xs sm:text-sm font-semibold w-6 h-6 sm:w-7 sm:h-7 flex items-center justify-center rounded-full ${isTodayDate ? 'bg-indigo-600 text-white' : ''}`}>{format(day, 'd')}</span>{count === 10 && <div className="text-green-500"><CheckIcon className="w-3 h-3 sm:w-4 sm:h-4"/></div>}</div><div className={`hidden sm:block relative z-10 text-[9px] font-bold px-1.5 py-0.5 rounded-md truncate w-full text-center my-1 ${getMessageStyle(count)}`}>{message}</div><div className="w-full space-y-1 mt-auto relative z-10"><div className="w-full bg-slate-100 dark:bg-slate-700 h-1 sm:h-1.5 rounded-full overflow-hidden"><div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div></div><div className="hidden sm:block text-[10px] font-bold text-slate-400 text-right">{count}/10</div></div></button> );})}</div> </> )}
