// HabitModal with Props for saving actions
const HabitModal: React.FC<{
    isOpen: boolean;
    date: string;
    onClose: () => void;
    habits: string[];
    checks: boolean[];
    onToggle: (index: number) => void;
    isReadOnly?: boolean;
    onRename?: (index: number, newName: string) => void;
    onReset?: () => void;
    onCustomize?: () => void;
    isCustomized?: boolean;
}> = ({ isOpen, date, onClose, habits, checks, onToggle, isReadOnly = false, onRename, onReset, onCustomize, isCustomized }) => {
    const [isClosing, setIsClosing] = useState(false);
    const [isVisible, setIsVisible] = useState(false);
    const [isLocked, setIsLocked] = useState(true);
    const [isEditingMode, setIsEditingMode] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setIsVisible(true);
            setIsClosing(false);
            setIsEditingMode(false);
        } else {
            setIsClosing(true);
            const timer = setTimeout(() => setIsVisible(false), 300);
            return () => clearTimeout(timer);
        }
    }, [isOpen]);

    useEffect(() => {
        if (isOpen) {
             const completed = checks.filter(Boolean).length;
             setIsLocked(completed === MAX_HABITS);
        }
    }, [checks, isOpen]);

    if (!isVisible && !isOpen) return null;

    const handleClose = () => {
        setIsClosing(true);
        setTimeout(onClose, 300);
    };

    const completedCount = checks.filter(Boolean).length;
    const isPerfect = completedCount === MAX_HABITS;
    const dateObj = parseISO(date);
    const formattedDate = format(dateObj, 'EEEE, MMMM do, yyyy');

    const handleInteraction = (index: number) => {
        if (isEditingMode || isReadOnly) return;
        if (isPerfect && isLocked) return;
        onToggle(index);
    };

    const modalContent = (
        <div 
            className={`fixed inset-0 z-[10005] flex items-end sm:items-center justify-center pointer-events-auto transition-all duration-300 ${isOpen && !isClosing ? 'bg-black/60 backdrop-blur-sm' : 'bg-black/0 pointer-events-none'}`}
            onClick={handleClose}
        >
            <div 
                className={`
                    w-full sm:max-w-md bg-white dark:bg-slate-900 rounded-t-2xl sm:rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90dvh]
                    transition-all duration-300 cubic-bezier(0.32, 0.72, 0, 1)
                    ${isOpen && !isClosing ? 'translate-y-0 opacity-100 scale-100' : 'translate-y-full sm:translate-y-10 opacity-0 sm:scale-95'}
                `}
                onClick={e => e.stopPropagation()}
            >
                <div className={`h-2 w-full bg-slate-100 dark:bg-slate-800`}>
                    <div className={`h-full transition-all duration-500 ease-out ${getScoreColor(completedCount)}`} style={{ width: `${(completedCount / MAX_HABITS) * 100}%` }} />
                </div>

                <div className="p-6 flex-1 overflow-y-auto">
                    <div className="flex justify-between items-start mb-6">
                        <div className="flex-1">
                            <div className="flex items-center gap-2 justify-between mr-2">
                                <div className="flex items-center gap-2">
                                    <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Daily Report</p>
                                    {isReadOnly && <span className="px-2 py-0.5 rounded bg-slate-200 dark:bg-slate-800 text-[10px] font-bold text-slate-500 flex items-center gap-1"><LockIcon className="w-3 h-3" /> Read Only</span>}
                                </div>
                                <button onClick={() => setIsEditingMode(!isEditingMode)} className={`text-xs font-bold px-3 py-1.5 rounded-lg transition-colors border ${isEditingMode ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700 hover:border-indigo-400'}`}>
                                    {isEditingMode ? 'Done' : 'Edit Habits'}
                                </button>
                            </div>
                            <h2 className="text-2xl font-extrabold text-slate-900 dark:text-white mt-1">{formattedDate}</h2>
                        </div>
                        <button onClick={handleClose} className="p-2 -mr-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"><XCircleIcon className="w-8 h-8" /></button>
                    </div>

                    {!isEditingMode && (
                        <div className="flex items-center justify-between mb-8 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800">
                            <div className="flex flex-col">
                                <span className="text-sm text-slate-500 dark:text-slate-400 font-medium">Progress</span>
                                <div className="flex items-baseline gap-1">
                                    <span className={`text-3xl font-black ${getScoreColor(completedCount, false)}`}>{completedCount}</span>
                                    <span className="text-sm text-slate-400 font-bold">/ {MAX_HABITS}</span>
                                </div>
                            </div>
                            {isPerfect ? <div className="flex items-center gap-2 px-3 py-1.5 bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 rounded-lg text-sm font-bold animate-pulse"><CheckIcon className="w-5 h-5" /> Completed</div> : <div className="text-right"><span className="text-xs font-bold uppercase text-slate-400 tracking-wider">Status</span><p className={`text-sm font-bold ${completedCount === 0 ? 'text-slate-500' : getScoreColor(completedCount, false)}`}>{completedCount === 0 ? 'Not Started' : 'In Progress'}</p></div>}
                        </div>
                    )}

                    {isEditingMode && (
                        <div className="mb-4 space-y-2">
                             {isCustomized ? (
                                <div className="p-3 bg-purple-50 dark:bg-purple-900/20 border border-purple-100 dark:border-purple-800 rounded-lg">
                                    <p className="text-xs text-purple-700 dark:text-purple-300 font-medium text-center">Custom habits for <strong>{format(dateObj, 'MMM do')}</strong>.</p>
                                    <button onClick={onReset} className="mt-2 w-full text-xs font-bold text-red-600 dark:text-red-400 hover:underline flex items-center justify-center gap-1"><RefreshIcon className="w-3 h-3" /> Reset to Global Defaults</button>
                                </div>
                             ) : (
                                <div className="p-3 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 rounded-lg">
                                    <p className="text-xs text-indigo-700 dark:text-indigo-300 font-medium text-center">Editing <strong>Global Defaults</strong>.</p>
                                    <button onClick={onCustomize} className="mt-2 w-full text-xs font-bold text-indigo-600 dark:text-indigo-400 hover:underline flex items-center justify-center gap-1"><PencilIcon className="w-3 h-3" /> Switch to Day-Specific Customization</button>
                                </div>
                             )}
                        </div>
                    )}

                    {isPerfect && isLocked && !isReadOnly && !isEditingMode && (
                        <div className="mb-6 flex justify-center">
                            <button onClick={() => setIsLocked(false)} className="text-sm text-indigo-600 dark:text-indigo-400 font-bold hover:underline flex items-center gap-2"><PencilIcon className="w-4 h-4" /> Unlock to Edit</button>
                        </div>
                    )}

                    <div className={`space-y-3 transition-opacity duration-300 ${(isPerfect && isLocked) || isReadOnly ? 'opacity-75' : 'opacity-100'}`}>
                         {habits.map((habit, index) => (
                             <div key={index}>
                                 {isEditingMode ? (
                                    <div className="flex items-center gap-2 mb-2 animate-fade-in">
                                        <span className="text-xs font-bold text-slate-400 w-6">{index + 1}.</span>
                                        <input type="text" value={habit} onChange={(e) => onRename && onRename(index, e.target.value)} className="flex-1 bg-white dark:bg-slate-800 border-2 border-indigo-100 dark:border-slate-700 rounded-lg px-3 py-3 text-sm font-bold text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all shadow-sm" placeholder={`Habit ${index + 1}`}/>
                                    </div>
                                 ) : (
                                     <label className={`flex items-center p-4 rounded-xl border transition-all select-none ${checks[index] ? 'bg-slate-50/50 dark:bg-slate-800/30 border-slate-200 dark:border-slate-700' : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800'} ${!isReadOnly && !((isPerfect && isLocked)) ? 'cursor-pointer hover:border-indigo-300 dark:hover:border-slate-600 hover:shadow-sm' : 'cursor-default'}`}>
                                         <div className={`w-6 h-6 rounded-md border-2 flex items-center justify-center transition-all duration-200 mr-4 ${checks[index] ? 'bg-indigo-600 border-indigo-600 text-white scale-110' : 'bg-transparent border-slate-300 dark:border-slate-600 group-hover:border-indigo-400'} ${isReadOnly ? 'opacity-60' : ''}`}>
                                             {checks[index] && <CheckIcon className="w-4 h-4 stroke-[3]" />}
                                         </div>
                                         <input type="checkbox" className="hidden" checked={checks[index]} onChange={() => handleInteraction(index)} disabled={(isPerfect && isLocked) || isReadOnly} />
                                         <span className={`text-base font-medium transition-all ${checks[index] ? 'text-slate-400 dark:text-slate-500 line-through decoration-slate-300 dark:decoration-slate-600' : 'text-slate-700 dark:text-slate-200'}`}>{habit}</span>
                                     </label>
                                 )}
                             </div>
                         ))}
                    </div>
                </div>
            </div>
        </div>
    );
    const root = document.getElementById('root') || document.body;
    return createPortal(modalContent, root);
};

