0 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors"><div className="sticky left-0 z-20 p-3 sm:p-4 flex items-center text-xs sm:text-sm font-semibold text-slate-700 dark:text-slate-300 truncate border-r border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]" title={habit}>{habit}</div>{eachDayOfInterval({ start: startOfWeek(currentDate), end: endOfWeek(currentDate) }).map(day => { const dStr = format(day, 'yyyy-MM-dd'); const checks = getDayChecks(dStr); const isChecked = checks[hIdx]; const isDayToday = isToday(day); return ( <div key={dStr} className={`p-2 sm:p-4 border-l border-slate-100 dark:border-slate-800 flex items-center justify-center ${isDayToday ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}><button onClick={() => onToggleHabit(dStr, hIdx)} disabled={!isDayToday} className={`w-6 h-6 sm:w-8 sm:h-8 rounded-lg flex items-center justify-center transition-all duration-200 ${isChecked ? 'bg-indigo-500 text-white shadow-md scale-110' : 'bg-slate-100 dark:bg-slate-700 text-transparent hover:bg-slate-200 dark:hover:bg-slate-600'} ${!isDayToday ? 'opacity-50 cursor-not-allowed' : ''}`}>{isChecked && <CheckIcon className="w-4 h-4 sm:w-5 sm:h-5"/>}</button></div> )})}</div>))}<div className="grid grid-cols-[150px_repeat(7,1fr)] sm:grid-cols-[200px_repeat(7,1fr)] bg-slate-50 dark:bg-slate-900/50 border-t border-slate-200 dark:border-slate-700"><div className="sticky left-0 z-20 p-4 font-bold text-xs text-slate-400 uppercase tracking-wider border-r border-slate-200 dark:border-slate-700 flex items-center bg-slate-50 dark:bg-slate-900 shadow-[2px_0_5px_-2px_rgba(0,0,0,0.1)]">Score</div>{eachDayOfInterval({ start: startOfWeek(currentDate), end: endOfWeek(currentDate) }).map(day => { const dStr = format(day, 'yyyy-MM-dd'); const count = getDayChecks(dStr).filter(Boolean).length; return ( <div key={dStr} className="p-2 sm:p-4 text-center border-l border-slate-200 dark:border-slate-800"><span className={`inline-block px-2 sm:px-3 py-1 rounded-full text-[10px] sm:text-xs font-bold text-white ${getPercentageColor(count * 10)}`}>{count}/10</span></div> )})}</div></div></div>)}
            </div>
        </div>
    );
};

