const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, onClose }) => {
    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');

    // DB State
    const [habitNames, setHabitNamesState] = useState<string[]>(DEFAULT_HABITS);
    const [dailyConfig, setDailyConfigState] = useState<Record<string, string[]>>({});
    const [logs, setLogsState] = useState<HabitLog>({});
    const [isLoading, setIsLoading] = useState(true);
    const { addNotification } = useNotificationState();

    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    const today = format(new Date(), 'yyyy-MM-dd');
    const todayChecks = logs[today] || Array(MAX_HABITS).fill(false);
    const todayCompleted = todayChecks.filter(Boolean).length;

    // FIX: Define stats and navItems here
    const stats = useMemo(() => {
        let totalLoggedDays = 0;
        let totalHabitsCompleted = 0;
        let perfectDays = 0;
        let streak = 0;

        Object.values(logs).forEach(checks => {
            if (checks) {
                totalLoggedDays++;
                const count = checks.filter(Boolean).length;
                totalHabitsCompleted += count;
                if (count === MAX_HABITS) perfectDays++;
            }
        });

        let checkDate = new Date();
        let dStr = format(checkDate, 'yyyy-MM-dd');

        const hasActivity = (date: string) => logs[date] && logs[date].some(Boolean);

        if (!hasActivity(dStr)) {
            checkDate = subDays(checkDate, 1);
            dStr = format(checkDate, 'yyyy-MM-dd');
        }

        while (hasActivity(dStr)) {
            streak++;
            checkDate = subDays(checkDate, 1);
            dStr = format(checkDate, 'yyyy-MM-dd');
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs]);

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <ClockIcon className="w-5 h-5"/> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5"/> },
        { id: 'reports', label: 'Reports', icon: <ChartBarIcon className="w-5 h-5"/> },
        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5"/> },
    ];
    // END FIX

    // Load Data
    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await getHabitData(user.id);
                if (data.habitNames.length > 0) setHabitNamesState(data.habitNames);
                setLogsState(data.logs);
                setDailyConfigState(data.dailyConfig);
            } catch (err) {
                console.error(err);
                addNotification({ title: "Error", message: "Failed to load habits.", type: "error" });
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, [user.id, addNotification]);

    // Realtime Sync
    useEffect(() => {
        const supabase = getSupabase();
        if (!supabase || isUsingMockData()) return;

        // Listen for habit_logs changes
        const logsChannel = supabase.channel(`habit_logs:${user.id}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'habit_logs', filter: `user_id=eq.${user.id}` }, (payload) => {
                 if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
                     const newLog = payload.new as any;
                     setLogsState(prev => ({ ...prev, [newLog.log_date]: newLog.checks }));
                     if (newLog.custom_habit_names) {
                         setDailyConfigState(prev => ({ ...prev, [newLog.log_date]: newLog.custom_habit_names }));
                     }
                 } else if (payload.eventType === 'DELETE') {
                     // Handle delete if needed
                     // setLogsState(prev => { const n = {...prev}; delete n[payload.old.log_date]; return n; })
                 }
            })
            .subscribe();

        // Listen for config changes
        const configChannel = supabase.channel(`habit_configs:${user.id}`)
             .on('postgres_changes', { event: '*', schema: 'public', table: 'habit_configs', filter: `user_id=eq.${user.id}` }, (payload) => {
                 if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
                     setHabitNamesState((payload.new as any).habit_names);
                 }
             })
             .subscribe();

        return () => {
            supabase.removeChannel(logsChannel);
            supabase.removeChannel(configChannel);
        };
    }, [user.id]);


    // Handlers
    const setHabitNames = (newNames: string[]) => {
        setHabitNamesState(newNames); // Optimistic
        saveHabitConfig(user.id, newNames); // DB
    };

    const setLogs = (newLogs: HabitLog) => {
        // This is tricky because setLogs usually takes a full object, but saveHabitLog takes one day.
        // We only use setLogs for full resets or specific day updates.
        // For reset all:
        if (Object.keys(newLogs).length === 0) {
            setLogsState({});
            deleteHabitLog(user.id);
            setDailyConfigState({});
            return;
        }
        // This fallback is rarely used directly now, prefer specific handlers
        setLogsState(newLogs); 
    };

    const handleToggleHabit = (date: string, index: number) => {
        if (date !== today) return; // Only allow toggling today in quick view

        const dayLogs = logs[date] ? [...logs[date]] : Array(MAX_HABITS).fill(false);
        dayLogs[index] = !dayLogs[index];

        // Optimistic
        setLogsState(prev => ({ ...prev, [date]: dayLogs }));

        // DB
        saveHabitLog(user.id, date, dayLogs, dailyConfig[date]);
    };

    // Handler passed to Modal (can edit any date)
    const onModalToggle = (index: number) => {
        if (!selectedDate) return;
        const dayLogs = logs[selectedDate] ? [...logs[selectedDate]] : Array(MAX_HABITS).fill(false);
        dayLogs[index] = !dayLogs[index];

        setLogsState(prev => ({ ...prev, [selectedDate]: dayLogs }));
        saveHabitLog(user.id, selectedDate, dayLogs, dailyConfig[selectedDate]);
    };

    const handleRenameHabit = (index: number, newName: string) => {
        if (!selectedDate) return;

        // Global
        const newGlobalNames = [...habitNames];
        newGlobalNames[index] = newName;
        setHabitNames(newGlobalNames); // Calls DB inside

        // Custom Day
        if (dailyConfig[selectedDate]) {
            const currentList = [...dailyConfig[selectedDate]];
            currentList[index] = newName;
            setDailyConfigState(prev => ({ ...prev, [selectedDate]: currentList }));

            // We need to save the log again to update the custom names column
            const checks = logs[selectedDate] || Array(MAX_HABITS).fill(false);
            saveHabitLog(user.id, selectedDate, checks, currentList);
        }
    };

    const handleCustomizeDay = () => {
        if (!selectedDate) return;
        const customNames = [...habitNames];
        setDailyConfigState(prev => ({ ...prev, [selectedDate]: customNames }));

        // Save to DB log entry
        const checks = logs[selectedDate] || Array(MAX_HABITS).fill(false);
        saveHabitLog(user.id, selectedDate, checks, customNames);
    };

    const handleResetDayHabits = () => {
        if (!selectedDate) return;
        const newConfig = { ...dailyConfig };
        delete newConfig[selectedDate];
        setDailyConfigState(newConfig);

        // Update DB to remove custom names (pass null/undefined)
        const checks = logs[selectedDate] || Array(MAX_HABITS).fill(false);
        saveHabitLog(user.id, selectedDate, checks, undefined);
    };

    const getHabitsForDate = (date: string) => {
        return dailyConfig[date] || habitNames;
    };

    const getDayChecks = (date: string) => {
        return logs[date] || Array(MAX_HABITS).fill(false);
    };

    if (isLoading && Object.keys(logs).length === 0) {
        return (
            <div className="h-full w-full flex items-center justify-center bg-slate-50 dark:bg-slate-900">
                <SpinnerIcon className="w-10 h-10 text-emerald-500 animate-spin" />
            </div>
        );
    }

    return (
        <div className="h-full w-full flex flex-col md:flex-row bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            <HabitModal 
                isOpen={!!selectedDate} 
                date={selectedDate || today} 
                onClose={() => setSelectedDate(null)} 
                habits={selectedDate ? getHabitsForDate(selectedDate) : habitNames}
                checks={selectedDate ? getDayChecks(selectedDate) : []}
                onToggle={onModalToggle}
                isReadOnly={false} // Allow retroactive edits
                onRename={(idx, val) => selectedDate && handleRenameHabit(idx, val)}
                onReset={() => selectedDate && handleResetDayHabits()}
                onCustomize={() => selectedDate && handleCustomizeDay()}
                isCustomized={!!selectedDate && !!dailyConfig[selectedDate]}
            />

            {/* Desktop Sidebar */}
            <aside className="hidden md:flex flex-col w-64 lg:w-72 border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 flex-shrink-0">
                <div className="p-6 border-b border-slate-100 dark:border-slate-800">
                    <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg text-emerald-600 dark:text-emerald-400">
                            <ClockIcon className="w-6 h-6" />
                        </div>
                        <h1 className="font-extrabold text-xl tracking-tight text-slate-900 dark:text-white">Consistency</h1>
                    </div>
                    <p className="text-xs text-slate-400 pl-1">Build better habits.</p>
                </div>

                <nav className="p-4 space-y-1 flex-1 overflow-y-auto">
                    {navItems.map(item => (
                        <button
                            key={item.id}
                            onClick={() => setView(item.id as any)}
                            className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-sm font-bold transition-all ${
                                view === item.id 
                                ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                                : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                            }`}
                        >
                            {item.icon}
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-100 dark:border-slate-800">
                    <div onClick={onClose} className="flex items-center gap-3 px-4 py-3 text-sm font-bold text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 cursor-pointer transition-colors rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800">
                        <ArrowLeftIcon className="w-5 h-5" /> Back to OS
                    </div>
                </div>
            </aside>

            {/* Mobile Top Bar */}
            <div className="md:hidden flex items-center justify-between p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 sticky top-0 z-20">
                 <div className="flex items-center gap-2 font-bold text-slate-900 dark:text-white text-lg">
                     <ClockIcon className="w-6 h-6 text-emerald-500" /> Consistency
                 </div>
                 <button onClick={onClose} className="p-2 text-slate-400 hover:bg-slate-100 rounded-full">
                     <XCircleIcon className="w-6 h-6" />
                 </button>
            </div>

            {/* Main Content Area */}
            <main className="flex-1 overflow-y-auto p-4 sm:p-8 bg-slate-50 dark:bg-slate-950/50 relative pb-24 md:pb-8 scroll-smooth">
                <div className="max-w-6xl mx-auto h-full flex flex-col">
                    <header className="mb-8 hidden md:block">
                        <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white capitalize tracking-tight">{view}</h2>
                        <p className="text-slate-500 dark:text-slate-400 mt-2 text-lg">
                            {view === 'dashboard' && "Track your daily discipline."}
                            {view === 'calendar' && "Visualize your consistency over time."}
                            {view === 'reports' && "Detailed history of your habits."}
                            {view === 'settings' && "Configure your 10 core habits."}
                        </p>
                    </header>

                    <div className="flex-1 min-h-0">
                        {view === 'dashboard' && (
                            <DashboardView 
                                todayCompleted={todayCompleted} 
                                stats={stats} 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate} 
                            />
                        )}
                        {view === 'calendar' && (
                            <CalendarView 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate} 
                                habitNames={habitNames}
                                onToggleHabit={handleToggleHabit} 
                            />
                        )}
                        {view === 'reports' && (
                            <ReportsView 
                                logs={logs} 
                                getDayChecks={getDayChecks} 
                                onSelectDate={setSelectedDate}
                                habitNames={habitNames}
                                dailyConfig={dailyConfig}
                            />
                        )}
                        {view === 'settings' && (
                            <SettingsView 
                                habitNames={habitNames} 
                                setHabitNames={setHabitNames} 
                                setLogs={setLogs} 
                                setDailyConfig={() => {}} // Not needed for bulk reset logic used inside
                                loading={isLoading}
                            />
                        )}
                    </div>
                </div>
            </main>

            {/* Mobile Bottom Navigation */}
            <nav className="md:hidden absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <div className="grid grid-cols-4 h-16">
                    {navItems.map(item => (
                        <BottomNavButton 
                            key={item.id}
                            icon={item.icon}
                            label={item.label}
                            isActive={view === item.id}
                            onClick={() => setView(item.id as any)}
                        />
                    ))}
                </div>
            </nav>
        </div>
    );
};

export default HabitTrackerPage;

-- Enable UUID extension if not already enabled
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 1. Habit Configurations (Stores the user's 10 default habit names)
CREATE TABLE IF NOT EXISTS public.habit_configs (
    user_id UUID REFERENCES public.users(id) ON DELETE CASCADE PRIMARY KEY,
    habit_names TEXT[] NOT NULL DEFAULT '{}'::TEXT[], -- Array of 10 strings
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE public.habit_configs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own habit config" 
ON public.habit_configs FOR SELECT 
USING (auth.uid() = user_id);

CREATE POLICY "Users can insert/update own habit config" 
ON public.habit_configs FOR INSERT 
WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can update own habit config" 
ON public.habit_configs FOR UPDATE 
USING (auth.uid() = user_id);

-- 2. Habit Logs (Stores daily checkmarks and day-specific overrides)
CREATE TABLE IF NOT EXISTS public.habit_logs (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID REFERENCES public.users(id) ON DELETE CASCADE NOT NULL,
    log_date DATE NOT NULL,
    checks BOOLEAN[] NOT NULL DEFAULT '{}'::BOOLEAN[], -- Array of 10 booleans
    custom_habit_names TEXT[], -- Optional: If set, overrides global config for this specific date
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, log_date) -- Ensure only one log entry per day per user
);

ALTER TABLE public.habit_logs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own habit logs" 
ON public.habit_logs FOR SELECT 
USING (auth.uid() = user_id);

CREATE POLICY "Users can insert own habit logs" 
ON public.habit_logs FOR INSERT 
WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can update own habit logs" 
ON public.habit_logs FOR UPDATE 
USING (auth.uid() = user_id);

