export const savePayload = async (payloadData: Partial<Payload>): Promise<Payload | null> => { let resultPayload: Payload; const isUpdate = !!payloadData.id; if (isUpdate) { const idx = inMemoryPayloads.findIndex(p => p.id === payloadData.id); if (idx > -1) { inMemoryPayloads[idx] = { ...inMemoryPayloads[idx], ...payloadData }; resultPayload = inMemoryPayloads[idx]; } else { resultPayload = { id: payloadData.id, created_at: new Date().toISOString(), title: 'Updating...', category: 'Other', code: '', is_visible: true, ...payloadData } as Payload; } } else { const newPayload: Payload = { id: crypto.randomUUID(), title: payloadData.title || 'New Payload', category: payloadData.category || 'Other', code: payloadData.code || '', description: payloadData.description || '', is_visible: payloadData.is_visible ?? true, created_at: new Date().toISOString() }; inMemoryPayloads.unshift(newPayload); resultPayload = newPayload; } return safeDbQuery(async () => { let query; if (isUpdate) { query = supabase!.from('payloads').update(payloadData).eq('id', payloadData.id).select('*').single(); } else { const { id, ...dataToInsert } = payloadData; query = supabase!.from('payloads').insert(dataToInsert).select('*').single(); } const { data, error } = await query; if (error) throw error; return { data: data as Payload, error: null }; }, resultPayload, "savePayload"); };
