const YearlyHeatmap: React.FC<{ logs: HabitLog }> = ({ logs }) => {
    const today = new Date();
    const startDate = subDays(today, 364);
    const allDays = eachDayOfInterval({ start: startDate, end: today });
    const startDay = getDay(startDate);
    const padDays = Array(startDay).fill(null);
    const gridItems = [...padDays, ...allDays];

    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6 mb-6">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider flex items-center gap-2">
                    <div className="p-1.5 bg-emerald-100 dark:bg-emerald-900/30 rounded-md text-emerald-600 dark:text-emerald-400">
                        <FireIcon className="w-4 h-4"/>
                    </div>
                    Yearly Consistency
                </h3>
             </div>

             <div className="overflow-x-auto pb-2">
                 <div className="inline-grid grid-rows-7 grid-flow-col gap-1 min-w-[700px]">
                     {gridItems.map((day, idx) => {
                         if (!day) return <div key={`pad-${idx}`} className="w-3 h-3" />;

                         const dateStr = format(day, 'yyyy-MM-dd');
                         const count = (logs[dateStr] || []).filter(Boolean).length;

                         return (
                             <div 
                                key={dateStr}
                                className={`w-3 h-3 rounded-[2px] transition-colors hover:ring-1 ring-slate-400 ${
                                    count === 0 ? 'bg-slate-100 dark:bg-slate-800/80' : 
                                    count <= 2 ? 'bg-red-500 dark:bg-red-600' : 
                                    count <= 5 ? 'bg-orange-400 dark:bg-orange-500' : 
                                    count <= 9 ? 'bg-blue-500 dark:bg-blue-600' : 
                                    'bg-emerald-500 dark:bg-emerald-500'
                                }`}
                                title={`${format(day, 'MMM do, yyyy')}: ${count} habits`}
                             />
                         )
                     })}
                 </div>
             </div>
        </div>
    )
};

const DonutChart: React.FC<{ data: { label: string; value: number; color: string }[], total: number }> = ({ data, total }) => {
    if (total === 0) return <div className="h-48 flex items-center justify-center text-slate-400 text-sm">No data to display</div>;
    let cumulativePercent = 0;
    const conicSegments = data.map((d) => {
        const start = cumulativePercent;
        const percent = (d.value / total) * 100;
        const end = start + percent;
        cumulativePercent = end;
        return `${d.color} ${start}% ${end}%`;
    }).join(', ');

    return (
        <div className="flex flex-col sm:flex-row items-center gap-8 justify-center p-4">
            <div className="relative w-48 h-48 flex-shrink-0">
                <div className="w-full h-full rounded-full shadow-lg" style={{ background: `conic-gradient(${conicSegments})` }}></div>
                <div className="absolute inset-8 bg-white dark:bg-slate-900 rounded-full flex flex-col items-center justify-center">
                    <span className="text-3xl font-black text-slate-800 dark:text-white">{total}</span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Days Logged</span>
                </div>
            </div>
            <div className="space-y-3 w-full sm:w-auto min-w-[160px]">
                {data.map(item => (
                    <div key={item.label} className="flex items-center justify-between gap-3 group">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                            <span className="text-sm font-medium text-slate-600 dark:text-slate-300">{item.label}</span>
                        </div>
                        <span className="text-sm font-bold text-slate-800 dark:text-white">{Math.round((item.value/total)*100)}%</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

const HorizontalBarChart: React.FC<{ data: { label: string; value: number; color: string; percentage: number }[] }> = ({ data }) => {
