};

const VerticalBarGraph: React.FC<{ data: { label: string; value: number; color: string }[] }> = ({ data }) => {
    if (data.length === 0) return <div className="h-48 flex items-center justify-center text-slate-400 text-sm">No trend data available</div>;
    const maxVal = Math.max(...data.map(d => d.value), 10);
    return (
        <div className="h-48 flex items-end gap-2 sm:gap-4 mt-4 px-2">
            {data.map((item, idx) => {
