    hasFallenBackToMock = true;
} else {
    try {
        supabase = createClient(supabaseUrl, supabaseAnonKey, {
            db: { schema: 'public' },
            auth: { 
                persistSession: true,
                autoRefreshToken: true,
                detectSessionInUrl: true 
