The error `policy "Users can view own habit config" for table "habit_configs" already exists` means parts of the migration ran successfully before, but now it's failing when trying to re-create things that already exist.

Here is the **corrected, safe-to-run SQL query**. It checks if tables and policies exist before creating them, so you can run it multiple times without errors.

### **Copy and Run this in Supabase SQL Editor:**

```sql
-- 1. Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 2. Create 'users' table if it is missing
CREATE TABLE IF NOT EXISTS public.users (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    email TEXT UNIQUE NOT NULL,
    name TEXT,
    avatar TEXT,
    role TEXT CHECK (role IN ('admin', 'user')) DEFAULT 'user',
    status TEXT DEFAULT 'unverified',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    is_2fa_enabled BOOLEAN DEFAULT FALSE,
    backup_codes TEXT[],
    writeup_access TEXT DEFAULT 'none',
    doc_access BOOLEAN DEFAULT FALSE,
    firebase_uid TEXT
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

-- Policies for Users (Safe checks)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Public profiles are viewable by everyone' AND tablename = 'users') THEN
        CREATE POLICY "Public profiles are viewable by everyone" ON public.users FOR SELECT USING (true);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can insert their own profile' AND tablename = 'users') THEN
        CREATE POLICY "Users can insert their own profile" ON public.users FOR INSERT WITH CHECK (auth.uid() = id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can update their own profile' AND tablename = 'users') THEN
        CREATE POLICY "Users can update their own profile" ON public.users FOR UPDATE USING (auth.uid() = id);
    END IF;
END $$;


-- 3. Create Habit Configurations Table
CREATE TABLE IF NOT EXISTS public.habit_configs (
    user_id UUID REFERENCES public.users(id) ON DELETE CASCADE PRIMARY KEY,
    habit_names TEXT[] NOT NULL DEFAULT '{}'::TEXT[],
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE public.habit_configs ENABLE ROW LEVEL SECURITY;

-- Policies for Habit Configs (Safe checks)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can view own habit config' AND tablename = 'habit_configs') THEN
        CREATE POLICY "Users can view own habit config" ON public.habit_configs FOR SELECT USING (auth.uid() = user_id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can insert own habit config' AND tablename = 'habit_configs') THEN
        CREATE POLICY "Users can insert own habit config" ON public.habit_configs FOR INSERT WITH CHECK (auth.uid() = user_id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can update own habit config' AND tablename = 'habit_configs') THEN
        CREATE POLICY "Users can update own habit config" ON public.habit_configs FOR UPDATE USING (auth.uid() = user_id);
    END IF;
END $$;


-- 4. Create Habit Logs Table
CREATE TABLE IF NOT EXISTS public.habit_logs (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    user_id UUID REFERENCES public.users(id) ON DELETE CASCADE NOT NULL,
    log_date DATE NOT NULL,
    checks BOOLEAN[] NOT NULL DEFAULT '{}'::BOOLEAN[],
    custom_habit_names TEXT[],
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(user_id, log_date)
);

ALTER TABLE public.habit_logs ENABLE ROW LEVEL SECURITY;

-- Policies for Habit Logs (Safe checks)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can view own habit logs' AND tablename = 'habit_logs') THEN
        CREATE POLICY "Users can view own habit logs" ON public.habit_logs FOR SELECT USING (auth.uid() = user_id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can insert own habit logs' AND tablename = 'habit_logs') THEN
        CREATE POLICY "Users can insert own habit logs" ON public.habit_logs FOR INSERT WITH CHECK (auth.uid() = user_id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can update own habit logs' AND tablename = 'habit_logs') THEN
        CREATE POLICY "Users can update own habit logs" ON public.habit_logs FOR UPDATE USING (auth.uid() = user_id);
    END IF;
END $$;


-- 5. Enable Realtime (Safe checks)
DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'habit_configs') THEN
    ALTER PUBLICATION supabase_realtime ADD TABLE public.habit_configs;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_publication_tables WHERE pubname = 'supabase_realtime' AND tablename = 'habit_logs') THEN
    ALTER PUBLICATION supabase_realtime ADD TABLE public.habit_logs;
  END IF;
END $$;
```

