CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- 2. Create 'users' table if it is missing
CREATE TABLE IF NOT EXISTS public.users (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    email TEXT UNIQUE NOT NULL,
    name TEXT,
    avatar TEXT,
    role TEXT CHECK (role IN ('admin', 'user')) DEFAULT 'user',
    status TEXT DEFAULT 'unverified',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    is_2fa_enabled BOOLEAN DEFAULT FALSE,
    backup_codes TEXT[],
    writeup_access TEXT DEFAULT 'none',
    doc_access BOOLEAN DEFAULT FALSE,
    firebase_uid TEXT
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

-- Policies for Users (Safe checks)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Public profiles are viewable by everyone' AND tablename = 'users') THEN
        CREATE POLICY "Public profiles are viewable by everyone" ON public.users FOR SELECT USING (true);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can insert their own profile' AND tablename = 'users') THEN
        CREATE POLICY "Users can insert their own profile" ON public.users FOR INSERT WITH CHECK (auth.uid() = id);
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can update their own profile' AND tablename = 'users') THEN
        CREATE POLICY "Users can update their own profile" ON public.users FOR UPDATE USING (auth.uid() = id);
    END IF;
END $$;

