    let anonKey: string | undefined;

    try {
        // @ts-ignore
        if (typeof import.meta !== 'undefined' && import.meta.env) {
            // @ts-ignore
            url = import.meta.env.VITE_SUPABASE_URL;
            // @ts-ignore
            anonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
        }
    } catch (e) { }

    if (!url || !anonKey) {
        const processEnv = (typeof window !== 'undefined' ? (window as any).process?.env : {}) || {};
        url = url || processEnv.SUPABASE_URL || processEnv.VITE_SUPABASE_URL;
        anonKey = anonKey || processEnv.SUPABASE_ANON_KEY || processEnv.VITE_SUPABASE_ANON_KEY;
    }

    return { url, anonKey };
};

