export interface HabitData {
    habitNames: string[];
    logs: Record<string, boolean[]>; // 'YYYY-MM-DD': [true, false...]
    dailyConfig: Record<string, string[]>; // 'YYYY-MM-DD': ['Name1', ...]
}

export const getHabitData = async (userId: string): Promise<HabitData> => {
    // Fallback Logic
    const fallback: HabitData = {
        habitNames: inMemoryHabitConfig[userId] || [],
        logs: {},
        dailyConfig: {}
    };
    if (inMemoryHabitLogs[userId]) {
        inMemoryHabitLogs[userId].forEach(log => {
            fallback.logs[log.log_date] = log.checks;
            if (log.custom_habit_names) {
                fallback.dailyConfig[log.log_date] = log.custom_habit_names;
            }
        });
    }

    return safeDbQuery(
        async () => {
            const { data: configData, error: configError } = await supabase!
                .from('habit_configs')
                .select('habit_names')
                .eq('user_id', userId)
                .single();

            // Handle missing row (PGRST116) gracefully
            if (configError && configError.code !== 'PGRST116') {
                throw configError;
            }

            const names = (configData?.habit_names) || [];

            const { data: logsData, error: logsError } = await supabase!
                .from('habit_logs')
                .select('log_date, checks, custom_habit_names')
                .eq('user_id', userId);

            if (logsError) throw logsError;

            const logs: Record<string, boolean[]> = {};
            const dailyConfig: Record<string, string[]> = {};

            (logsData || []).forEach((row: any) => {
                logs[row.log_date] = row.checks;
                if (row.custom_habit_names) {
                    dailyConfig[row.log_date] = row.custom_habit_names;
                }
            });

            return { data: { habitNames: names, logs, dailyConfig }, error: null };
        },
        fallback,
        "getHabitData"
    );
};

export const saveHabitConfig = async (userId: string, names: string[]): Promise<boolean> => {
    // Fallback
    inMemoryHabitConfig[userId] = names;

    return safeDbQuery(
        async () => {
            // Upsert config
            const { error } = await supabase!
                .from('habit_configs')
                .upsert({ user_id: userId, habit_names: names });

            if (error) {
                console.error("Error saving habit config:", error);
                throw error;
            }
            return { data: true, error: null };
        },
        true,
        "saveHabitConfig"
    );
};

export const saveHabitLog = async (userId: string, date: string, checks: boolean[], customNames?: string[]): Promise<boolean> => {
    // Fallback
    if (!inMemoryHabitLogs[userId]) inMemoryHabitLogs[userId] = [];
    const existingIdx = inMemoryHabitLogs[userId].findIndex(l => l.log_date === date);
    const newLog = { log_date: date, checks, custom_habit_names: customNames };

    if (existingIdx > -1) {
        inMemoryHabitLogs[userId][existingIdx] = newLog;
    } else {
        inMemoryHabitLogs[userId].push(newLog);
    }

    return safeDbQuery(
        async () => {
            const { error } = await supabase!
                .from('habit_logs')
                .upsert({ 
                    user_id: userId, 
                    log_date: date, 
                    checks: checks,
                    custom_habit_names: customNames || null 
                }, { onConflict: 'user_id, log_date' });

            if (error) {
                 console.error("Error saving habit log:", error);
                 throw error;
            }
            return { data: true, error: null };
        },
        true,
        "saveHabitLog"
    );
};

export const deleteHabitLog = async (userId: string, date?: string): Promise<boolean> => {
    // Fallback
    if (date) {
        if (inMemoryHabitLogs[userId]) {
            inMemoryHabitLogs[userId] = inMemoryHabitLogs[userId].filter(l => l.log_date !== date);
        }
    } else {
         // Delete All
         inMemoryHabitLogs[userId] = [];
    }

    return safeDbQuery(
        async () => {
            let query = supabase!.from('habit_logs').delete().eq('user_id', userId);
            if (date) {
                query = query.eq('log_date', date);
            }
            const { error } = await query;
            if (error) throw error;
            return { data: true, error: null };
        },
        true,
        "deleteHabitLog"
    );
};

