import { MOCK_ACTIVITY_LOG } from '../data/activityLog';

// ... (keep existing credentials, supabase client init, mock data variables)

const getSupabaseCredentials = () => {
    let url: string | undefined;
    let anonKey: string | undefined;

    try {
        // @ts-ignore
        if (typeof import.meta !== 'undefined' && import.meta.env) {
            // @ts-ignore
            url = import.meta.env.VITE_SUPABASE_URL;
            // @ts-ignore
            anonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
        }
    } catch (e) { }

    if (!url || !anonKey) {
        const processEnv = (typeof window !== 'undefined' ? (window as any).process?.env : {}) || {};
        url = url || processEnv.SUPABASE_URL || processEnv.VITE_SUPABASE_URL;
        anonKey = anonKey || processEnv.SUPABASE_ANON_KEY || processEnv.VITE_SUPABASE_ANON_KEY;
    }

    return { url, anonKey };
};

const { url: supabaseUrl, anonKey: supabaseAnonKey } = getSupabaseCredentials();

let supabase: SupabaseClient | null = null;
let hasFallenBackToMock = false;

if (!supabaseUrl || !supabaseAnonKey || supabaseUrl.includes("example.com") || supabaseUrl === "undefined") {
    console.warn("Supabase credentials not found or are placeholders. Falling back to mock data mode.");
    hasFallenBackToMock = true;
} else {
    try {
        supabase = createClient(supabaseUrl, supabaseAnonKey, {
            db: { schema: 'public' },
            auth: { 
                persistSession: true,
                autoRefreshToken: true,
                detectSessionInUrl: true 
