async function safeDbQuery<T>(
    operation: () => Promise<{ data: any; error: any }>,
    fallbackValue: T,
    context: string
): Promise<T> {
    if (!supabase || hasFallenBackToMock) {
        return Promise.resolve(fallbackValue);
    }

    try {
        const { data, error } = await operation();
        if (error) throw error;
        return data as T;
    } catch (error: any) {
        const msg = (error.message || error.toString()).toLowerCase();
        // 42P01 is PostgreSQL error code for "undefined_table"
        // PGRST200 is PostgREST error for schema cache miss
        // PGRST205 is PostgREST error for "Relation not found in schema cache" (often needs cache reload)
        if (
            error.code === '42P01' || 
            error.code === 'PGRST200' ||
            error.code === 'PGRST205' ||
            (msg.includes('relation') && msg.includes('does not exist')) ||
            msg.includes('schema cache') || 
            msg.includes('could not find the table')
        ) {
            console.info(`[Database] Table missing or schema cache stale for ${context}. App working with local data. Hint: Run the SQL migration and reload the schema cache.`);
        } else {
            console.error(`[Database Error] in ${context}:`, error.message || error);
        }
        return fallbackValue;
    }
}

export const sanitizeUser = (user: any): User => {
    if (!user) return user;
    return {
        ...user,
