        <div className={`p-4 rounded-xl ${colorClass} bg-opacity-10 ${textColorClass}`}>{icon}</div>
        <div><p className="text-2xl sm:text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">{value}</p><p className="text-xs font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500 mt-1">{label}</p></div>
    </div>
);

