        <div className={`mb-1 transition-transform duration-200 ${isActive ? 'scale-110' : 'scale-100'}`}>{React.cloneElement(icon as React.ReactElement, { className: 'w-6 h-6' })}</div><span className="text-[10px] font-bold">{label}</span>
    </button>
);

