            {viewMode === 'analytics' && ( <> <YearlyHeatmap logs={logs} /> <div className="grid grid-cols-1 md:grid-cols-2 gap-6"> <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6"> <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2"><div className="p-1.5 bg-indigo-100 dark:bg-indigo-900/30 rounded-md text-indigo-600 dark:text-indigo-400"><PieChartIcon className="w-4 h-4"/></div>Consistency Breakdown</h3> <DonutChart data={pieData} total={totalDays} /> </div> <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6"> <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2"><div className="p-1.5 bg-emerald-100 dark:bg-emerald-900/30 rounded-md text-emerald-600 dark:text-emerald-400"><ListIcon className="w-4 h-4"/></div>Habit Performance</h3> <HorizontalBarChart data={barData} /> </div> <div className="md:col-span-2 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6"> <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2"><div className="p-1.5 bg-purple-100 dark:bg-purple-900/30 rounded-md text-purple-600 dark:text-purple-400"><ChartBarIcon className="w-4 h-4"/></div>Monthly Average Score</h3> {monthlyData.length > 0 ? ( <VerticalBarGraph data={monthlyData} /> ) : ( <div className="h-32 flex items-center justify-center text-slate-400 text-sm">Insufficient data for trends</div> )} </div> </div> </> )}
            {viewMode === 'history' && ( <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden"> <div className="divide-y divide-slate-100 dark:divide-slate-700"> {sortedDates.length === 0 && ( <div className="p-12 text-center text-slate-500 dark:text-slate-400"> No data recorded yet. </div> )} {sortedDates.map(date => { const count = getDayChecks(date).filter(Boolean).length; return ( <div key={date} onClick={() => onSelectDate(date)} className="p-4 sm:p-5 hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors flex items-center justify-between group"> <div className="flex items-center gap-4"> <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg text-white shadow-sm ${getScoreColor(count)}`}> {count} </div> <div> <p className="font-bold text-slate-900 dark:text-white">{format(parseISO(date), 'MMMM do, yyyy')}</p> <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wide">{format(parseISO(date), 'EEEE')}</p> </div> </div> <ChevronDownIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" /> </div> ); })} </div> </div> )}
        </div>
    );
};

