const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, onClose }) => {
    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');

    // DB State
    const [habitNames, setHabitNamesState] = useState<string[]>(DEFAULT_HABITS);
    const [dailyConfig, setDailyConfigState] = useState<Record<string, string[]>>({});
    const [logs, setLogsState] = useState<HabitLog>({});
    const [isLoading, setIsLoading] = useState(true);
    const { addNotification } = useNotificationState();

    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    const today = format(new Date(), 'yyyy-MM-dd');
    const todayChecks = logs[today] || Array(MAX_HABITS).fill(false);
    const todayCompleted = todayChecks.filter(Boolean).length;

    const stats = useMemo(() => {
        let totalLoggedDays = 0;
        let totalHabitsCompleted = 0;
        let perfectDays = 0;
        let streak = 0;

        Object.values(logs).forEach((checks: any) => {
            if (checks) {
                totalLoggedDays++;
                const count = (checks as boolean[]).filter(Boolean).length;
                totalHabitsCompleted += count;
                if (count === MAX_HABITS) perfectDays++;
            }
        });

        let checkDate = new Date();
        let dStr = format(checkDate, 'yyyy-MM-dd');

        const hasActivity = (date: string) => logs[date] && logs[date].some(Boolean);

        if (!hasActivity(dStr)) {
            checkDate = subDays(checkDate, 1);
            dStr = format(checkDate, 'yyyy-MM-dd');
        }

        while (hasActivity(dStr)) {
            streak++;
            checkDate = subDays(checkDate, 1);
            dStr = format(checkDate, 'yyyy-MM-dd');
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs]);

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <ClockIcon className="w-5 h-5"/> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5"/> },
        { id: 'reports', label: 'Reports', icon: <ChartBarIcon className="w-5 h-5"/> },
        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5"/> },
    ];

    // Load Data
    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            try {
                const data = await getHabitData(user.id);
                if (data.habitNames.length > 0) setHabitNamesState(data.habitNames);
                setLogsState(data.logs);
                setDailyConfigState(data.dailyConfig);
            } catch (err) {
                console.error(err);
                addNotification({ title: "Error", message: "Failed to load habits.", type: "error" });
            } finally {
                setIsLoading(false);
            }
        };
        loadData();
    }, [user.id, addNotification]);

    // Realtime Sync
    useEffect(() => {
        const supabase = getSupabase();
        if (!supabase || isUsingMockData()) return;

        const logsChannel = supabase.channel(`habit_logs:${user.id}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'habit_logs', filter: `user_id=eq.${user.id}` }, (payload) => {
                 if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
                     const newLog = payload.new as any;
                     setLogsState(prev => ({ ...prev, [newLog.log_date]: newLog.checks }));
                     if (newLog.custom_habit_names) {
                         setDailyConfigState(prev => ({ ...prev, [newLog.log_date]: newLog.custom_habit_names }));
                     }
                 }
                 if (payload.eventType === 'DELETE') {
                     const oldLog = payload.old as any;
                     // Only remove if we are tracking this date locally
                     setLogsState(prev => {
                         const next = { ...prev };
                         delete next[oldLog.log_date];
                         return next;
                     });
                 }
            })
            .subscribe();

        return () => { supabase.removeChannel(logsChannel); };
    }, [user.id]);

    const handleToggle = (dateStr: string, index: number) => {
        const currentChecks = logs[dateStr] || Array(MAX_HABITS).fill(false);
        const newChecks = [...currentChecks];
        newChecks[index] = !newChecks[index];

        // Optimistic update
        setLogsState(prev => ({ ...prev, [dateStr]: newChecks }));

        // Persist
        const currentDayConfig = dailyConfig[dateStr]; // Pass custom names if they exist for this day
        saveHabitLog(user.id, dateStr, newChecks, currentDayConfig).catch(err => {
             console.error("Failed to save log", err);
             // Revert on error
             setLogsState(prev => ({ ...prev, [dateStr]: currentChecks }));
             addNotification({ title: "Error", message: "Failed to save progress.", type: "error" });
        });
    };

    const handleHabitRename = (index: number, newName: string) => {
        const newNames = [...habitNames];
        newNames[index] = newName;

        if (selectedDate && selectedDate !== today) {
            // Renaming for a specific past day (Customization)
            setDailyConfigState(prev => ({ ...prev, [selectedDate]: newNames }));
            // We need to save the log row with the new custom names array
            const currentChecks = logs[selectedDate] || Array(MAX_HABITS).fill(false);
            saveHabitLog(user.id, selectedDate, currentChecks, newNames);
        } else {
             // Renaming global defaults
            setHabitNamesState(newNames);
            saveHabitConfig(user.id, newNames);
        }
    };

    const handleCustomizeDay = () => {
        if (!selectedDate) return;
        // Copy global habits to this day to start customizing
        const currentDayConfig = dailyConfig[selectedDate] || [...habitNames];
        setDailyConfigState(prev => ({ ...prev, [selectedDate]: currentDayConfig }));
    };

    const handleResetDay = () => {
        if (!selectedDate) return;
        setDailyConfigState(prev => {
            const next = { ...prev };
            delete next[selectedDate];
            return next;
        });
        const currentChecks = logs[selectedDate] || Array(MAX_HABITS).fill(false);
        // Save with null custom_names to revert to default
        saveHabitLog(user.id, selectedDate, currentChecks, undefined); 
    };

    const getDayChecks = (dateStr: string) => logs[dateStr] || Array(MAX_HABITS).fill(false);
    const getCurrentHabitNames = (dateStr: string) => dailyConfig[dateStr] || habitNames;

    return (
        <div className="h-full w-full bg-slate-50 dark:bg-slate-900 flex flex-col relative overflow-hidden">
            {/* Header */}
            <header className="px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-b border-slate-200 dark:border-slate-700 flex justify-between items-center z-10 sticky top-0">
                <div className="flex items-center gap-3">
                    <h1 className="text-xl font-bold text-slate-800 dark:text-white tracking-tight flex items-center gap-2">
                        <HabitTrackerIcon className="w-6 h-6 text-indigo-500" />
                        Habit Tracker
                    </h1>
                </div>
                {onClose && (
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                        <XCircleIcon className="w-6 h-6" />
                    </button>
                )}
            </header>

            {/* Scrollable Content */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 lg:p-8 custom-scrollbar">
                <div className="max-w-5xl mx-auto">
                    {isLoading ? (
                        <div className="flex justify-center py-20"><SpinnerIcon className="w-10 h-10 text-indigo-500 animate-spin"/></div>
                    ) : (
                        <>
                           {view === 'dashboard' && <DashboardView todayCompleted={todayCompleted} stats={stats} getDayChecks={getDayChecks} onSelectDate={setSelectedDate} />}
                           {view === 'calendar' && <CalendarView getDayChecks={getDayChecks} onSelectDate={setSelectedDate} habitNames={habitNames} onToggleHabit={handleToggle} />}
                           {view === 'reports' && <ReportsView logs={logs} getDayChecks={getDayChecks} onSelectDate={setSelectedDate} habitNames={habitNames} dailyConfig={dailyConfig} />}
                           {view === 'settings' && <SettingsView habitNames={habitNames} setHabitNames={(names) => { setHabitNamesState(names); saveHabitConfig(user.id, names); }} setLogs={setLogsState} setDailyConfig={setDailyConfigState} loading={isLoading} />}
                        </>
                    )}
                </div>
            </div>

            {/* Bottom Nav */}
            <div className="bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex justify-around p-1 pb-safe z-10">
                {navItems.map(item => (
                    <BottomNavButton 
                        key={item.id} 
                        icon={item.icon} 
                        label={item.label} 
                        isActive={view === item.id} 
                        onClick={() => setView(item.id as any)} 
                    />
                ))}
            </div>

            {/* Detail Modal */}
            <HabitModal 
                isOpen={!!selectedDate} 
                date={selectedDate || today} 
                onClose={() => setSelectedDate(null)} 
                habits={getCurrentHabitNames(selectedDate || today)} 
                checks={getDayChecks(selectedDate || today)} 
                onToggle={(idx) => selectedDate && handleToggle(selectedDate, idx)}
                isReadOnly={false} // Allow editing any day
                onRename={handleHabitRename}
                isCustomized={!!(selectedDate && dailyConfig[selectedDate])}
                onCustomize={handleCustomizeDay}
                onReset={handleResetDay}
            />
        </div>
    );
};

export default HabitTrackerPage;
